export default function LedgerDotMesh(){const [active,setActive]=useState(1);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">locator field</p><div className="relative mt-4 grid h-36 grid-cols-6 grid-rows-4 place-items-center rounded-2xl bg-[#f4f5f6]">{Array.from({length:24},(_,i)=><i key={i} aria-hidden className="h-1.5 w-1.5 rounded-full bg-[#d5d6d8]"/>)}<motion.i aria-hidden className="absolute h-4 w-4 rounded-full bg-[#ff9950] shadow-[0_0_0_5px_rgba(255,153,80,.18)]" animate={{left:points[active][1].split(",")[0],top:points[active][1].split(",")[1]}} transition={reduced?{duration:0}:{type:"spring",stiffness:280,damping:24}}/></div><div className="mt-3 grid grid-cols-3 gap-2">{points.map((point,i)=><button key={point[0]} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] text-xs font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{point[0]}</button>)}</div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Locator moved to {points[active][0]}.</p></section>}
